selector_to_html = {"a[href=\"wireless.html#modify-device-id\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0639\u062f\u064a\u0644 \u0645\u0639\u0631\u0641 \u0627\u0644\u062c\u0647\u0627\u0632<a class=\"headerlink\" href=\"#modify-device-id\" title=\"Link to this heading\">#</a></h2>", "a[href=\"bluetooth.html#bluetooth-spp\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">PP \u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b<a class=\"headerlink\" href=\"#bluetooth-spp\" title=\"Link to this heading\">#</a></h2>", "a[href=\"bluetooth.html#bluetooth-keyboard-transmission-speed\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0633\u0631\u0639\u0629 \u0646\u0642\u0644 \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0641\u0627\u062a\u064a\u062d \u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b<a class=\"headerlink\" href=\"#bluetooth-keyboard-transmission-speed\" title=\"Link to this heading\">#</a></h2><h3>\u0633\u0631\u0639\u0629 \u0639\u0627\u0644\u064a\u0629<a class=\"headerlink\" href=\"#high-speed\" title=\"Link to this heading\">#</a></h3>", "a[href=\"working.html#storage-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u062a\u062e\u0632\u064a\u0646<a class=\"headerlink\" href=\"#storage-mode\" title=\"Link to this heading\">#</a></h2><h3>\u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a <a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#data-upload1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0646\u0638\u0627\u0645<a class=\"headerlink\" href=\"#system-settings\" title=\"Link to this heading\">#</a></h1><h2>\u0625\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>\u0639\u0646\u062f \u062d\u062f\u0648\u062b \u062e\u0637\u0623 \u063a\u064a\u0631 \u0645\u0639\u0631\u0648\u0641 \u0639\u0644\u0649 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a\u060c \u064a\u0645\u0643\u0646\u0643 \u0625\u0639\u0627\u062f\u0629 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0639\u0646 \u0637\u0631\u064a\u0642 \u0627\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629.</p>", "a[href=\"wireless.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0625\u0631\u0633\u0627\u0644 Wi-Fi<a class=\"headerlink\" href=\"#wi-fi-transmission-mode\" title=\"Link to this heading\">#</a></h1><h2>\u062a\u0639\u062f\u064a\u0644 \u0645\u0639\u0631\u0641 \u0627\u0644\u062c\u0647\u0627\u0632<a class=\"headerlink\" href=\"#modify-device-id\" title=\"Link to this heading\">#</a></h2>", "a[href=\"wireless.html#data-transmission-protocol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0628\u0631\u0648\u062a\u0648\u0643\u0648\u0644 \u0646\u0642\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a<a class=\"headerlink\" href=\"#data-transmission-protocol\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#get-firmware-version\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0646\u0633\u062e\u0629 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062c \u0627\u0644\u062b\u0627\u0628\u062a<a class=\"headerlink\" href=\"#get-firmware-version\" title=\"Link to this heading\">#</a></h2>", "a[href=\"wireless.html#network-configuration\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0643\u0648\u064a\u0646 \u0627\u0644\u0634\u0628\u0643\u0629<a class=\"headerlink\" href=\"#network-configuration\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#battery-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0628\u0637\u0627\u0631\u064a\u0629<a class=\"headerlink\" href=\"#battery-information\" title=\"Link to this heading\">#</a></h2>", "a[href=\"working.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u0639\u0645\u0644<a class=\"headerlink\" href=\"#working-mode\" title=\"Link to this heading\">#</a></h1><p>\u0641\u064a \u0645\u062c\u0627\u0644 \u0627\u0644\u0639\u0645\u0644 \u062e\u0627\u0631\u062c \u0646\u0637\u0627\u0642 \u0627\u0644\u0645\u062c\u0627\u0644 2. G \u0627\u0644\u0645\u0633\u062a\u0642\u0628\u0650\u0644 \u0623\u0648 \u0625\u0634\u0627\u0631\u0629 \u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b\u060c \u064a\u0645\u0643\u0646\u0643 \u062a\u0646\u0634\u064a\u0637 \u0648\u0636\u0639 \u062a\u062e\u0632\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0628\u0627\u062a\u0628\u0627\u0639 \u0627\u0644\u062e\u0637\u0648\u0627\u062a \u0627\u0644\u0645\u0628\u064a\u0646\u0629 \u0623\u062f\u0646\u0627\u0647. \u0641\u064a \u0647\u0630\u0627 \u0627\u0644\u0648\u0636\u0639\u060c \u0633\u064a\u062a\u0645 \u062a\u062e\u0632\u064a\u0646 \u062c\u0645\u064a\u0639 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0645\u0645\u0633\u0648\u062d\u0629 \u0636\u0648\u0626\u064a\u0627 \u0645\u0628\u0627\u0634\u0631\u0629 \u0641\u064a \u0627\u0644\u0645\u0627\u0633\u062d. \u0642\u0628\u0644 \u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a\u060c \u0633\u064a\u062a\u0645 \u062d\u0641\u0638\u0647 \u0628\u0634\u0643\u0644 \u062f\u0627\u0626\u0645 \u0641\u064a \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u062d\u062a\u0649 \u062a\u062a\u0645\u0643\u0646 \u0645\u0646 \u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0639\u0646\u062f\u0645\u0627 \u064a\u0643\u0648\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0641\u064a \u0646\u0637\u0627\u0642 \u0625\u0634\u0627\u0631\u0629 \u0627\u0644\u0627\u0633\u062a\u0644\u0627\u0645.</p>", "a[href=\"wireless.html#data-rceiving-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0646\u0633\u064a\u0642 \u062a\u0635\u0648\u064a\u0631 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a<a class=\"headerlink\" href=\"#data-rceiving-format\" title=\"Link to this heading\">#</a></h2><h3>\u0627\u0644\u0631\u0645\u0632 \u0627\u0644\u0635\u0648\u062a\u064a<a class=\"headerlink\" href=\"#voice-code\" title=\"Link to this heading\">#</a></h3>", "a[href=\"bluetooth.html#clear-pairing-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0645\u0633\u062d \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0627\u0644\u0627\u0642\u062a\u0631\u0627\u0646<a class=\"headerlink\" href=\"#clear-pairing-information\" title=\"Link to this heading\">#</a></h2>", "a[href=\"keyboard.html#keyboard-language\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0644\u063a\u0629 \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0641\u0627\u062a\u064a\u062d<a class=\"headerlink\" href=\"#keyboard-language\" title=\"Link to this heading\">#</a></h2><h3>\u0627\u062d\u0635\u0644 \u0639\u0644\u0649 \u0644\u063a\u0629 \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0641\u0627\u062a\u064a\u062d \u0627\u0644\u062d\u0627\u0644\u064a\u0629<a class=\"headerlink\" href=\"#get-current-keyboard-language\" title=\"Link to this heading\">#</a></h3>", "a[href=\"bluetooth.html#bluetooth-hid\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b \u0639\u0627\u0644\u064a \u0627\u0644\u062c\u0648\u062f\u0629<a class=\"headerlink\" href=\"#bluetooth-hid\" title=\"Link to this heading\">#</a></h2>", "a[href=\"working.html#normal-mode\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0627\u0644\u0648\u0636\u0639 \u0627\u0644\u0639\u0627\u062f\u064a<a class=\"headerlink\" href=\"#normal-mode\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#wifi-wireless-scanner-quick-setup-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><strong>WiFi</strong> \u062f\u0644\u064a\u0644 \u0627\u0644\u0625\u0639\u062f\u0627\u062f \u0627\u0644\u0633\u0631\u064a\u0639 \u0644\u0644\u0645\u0633\u062d \u0627\u0644\u0644\u0627\u0633\u0644\u0643\u064a<a class=\"headerlink\" href=\"#wifi-wireless-scanner-quick-setup-guide\" title=\"Link to this heading\">#</a></h1>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>\u0639\u0646\u062f \u062d\u062f\u0648\u062b \u062e\u0637\u0623 \u063a\u064a\u0631 \u0645\u0639\u0631\u0648\u0641 \u0639\u0644\u0649 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a\u060c \u064a\u0645\u0643\u0646\u0643 \u0625\u0639\u0627\u062f\u0629 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0639\u0646 \u0637\u0631\u064a\u0642 \u0627\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0627\u0641\u062a\u0631\u0627\u0636\u064a\u0629.</p>", "a[href=\"bluetooth.html#bluetooth-ble\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Bluetooth BLE<a class=\"headerlink\" href=\"#bluetooth-ble\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u0635\u0648\u062a<a class=\"headerlink\" href=\"#volume-settings\" title=\"Link to this heading\">#</a></h2><p>\u0645\u0633\u062d \u0631\u0645\u0632 \u0627\u0644\u0625\u0639\u062f\u0627\u062f \u0627\u0644\u0645\u0642\u0627\u0628\u0644 \u0644\u062a\u0634\u063a\u064a\u0644/\u0625\u064a\u0642\u0627\u0641 \u0645\u0648\u062c\u0647 \u0627\u0644\u0635\u0648\u062a \u0645\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a</p>", "a[href=\"bluetooth.html#modify-bluetooth-name\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0639\u062f\u064a\u0644 \u0627\u0633\u0645 \u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b<a class=\"headerlink\" href=\"#modify-bluetooth-name\" title=\"Link to this heading\">#</a></h2>", "a[href=\"bluetooth.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0636\u0639 \u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b<a class=\"headerlink\" href=\"#bluetooth-mode\" title=\"Link to this heading\">#</a></h1><h2>\u0627\u0644\u0628\u0644\u0648\u062a\u0648\u062b \u0639\u0627\u0644\u064a \u0627\u0644\u062c\u0648\u062f\u0629<a class=\"headerlink\" href=\"#bluetooth-hid\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#sleep-time\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0648\u0642\u062a \u0627\u0644\u0646\u0648\u0645<a class=\"headerlink\" href=\"#sleep-time\" title=\"Link to this heading\">#</a></h2><p>\u0639\u0646 \u0637\u0631\u064a\u0642 \u0645\u0633\u062d \u0631\u0645\u0632 \u0627\u0644\u0625\u0639\u062f\u0627\u062f \u0627\u0644\u062a\u0627\u0644\u064a\u060c \u064a\u0645\u0643\u0646\u0643 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0627\u0633\u062d \u0627\u0644\u0636\u0648\u0626\u064a \u0644\u0644\u062f\u062e\u0648\u0644 \u0641\u064a \u0648\u0636\u0639 \u0627\u0644\u0633\u0643\u0648\u0646 \u0628\u0639\u062f \u0641\u062a\u0631\u0629 \u0632\u0645\u0646\u064a\u0629 \u0645\u0639\u064a\u0646\u0629 \u0639\u0646\u062f\u0645\u0627 \u0644\u0627 \u064a\u062a\u0645 \u0645\u0633\u062d \u0627\u0644\u062a\u0639\u0644\u064a\u0645\u0627\u062a \u0627\u0644\u0628\u0631\u0645\u062c\u064a\u0629\u060c \u0645\u0646 \u0623\u062c\u0644 \u0627\u0644\u062d\u062f \u0645\u0646 \u0627\u0633\u062a\u0647\u0644\u0627\u0643 \u0627\u0644\u0637\u0627\u0642\u0629.</p>", "a[href=\"wireless.html#data-upload-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u062a\u0646\u0633\u064a\u0642 \u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a<a class=\"headerlink\" href=\"#data-upload-format\" title=\"Link to this heading\">#</a></h2><h3>\u0645\u062d\u062a\u0648\u0649 \u0627\u0644\u0628\u0627\u0631\u0643\u0648\u062f \u0627\u0644\u0623\u0635\u0644\u064a <a class=\"footnote-reference brackets\" href=\"#id2\" id=\"id1\" role=\"doc-noteref\"><span class=\"fn-bracket\">[</span>1<span class=\"fn-bracket\">]</span></a><a class=\"headerlink\" href=\"#original-barcode-content1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"keyboard.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0641\u0627\u062a\u064a\u062d<a class=\"headerlink\" href=\"#keyboard-settings\" title=\"Link to this heading\">#</a></h1><h2>\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u062d\u0627\u0644\u0629<a class=\"headerlink\" href=\"#case-settings\" title=\"Link to this heading\">#</a></h2><h3>\u0639\u0627\u062f\u064a<a class=\"headerlink\" href=\"#normal\" title=\"Link to this heading\">#</a></h3>", "a[href=\"keyboard.html#case-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u0627\u0644\u062d\u0627\u0644\u0629<a class=\"headerlink\" href=\"#case-settings\" title=\"Link to this heading\">#</a></h2><h3>\u0639\u0627\u062f\u064a<a class=\"headerlink\" href=\"#normal\" title=\"Link to this heading\">#</a></h3>", "a[href=\"bluetooth.html#ios-popup-hide-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">\u0645\u0646\u0628\u062b\u0642\u0629/\u0625\u062e\u0641\u0627\u0621 \u0644\u0648\u062d\u0629 \u0627\u0644\u0645\u0641\u0627\u062a\u064a\u062d<a class=\"headerlink\" href=\"#ios-popup-hide-keyboard\" title=\"Link to this heading\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
